1	/**
2	 * GSD Detection — Project state and ecosystem detection.
3	 *
4	 * Pure functions, zero UI dependencies, zero side effects.
5	 * Used by init-wizard.ts and guided-flow.ts to determine what onboarding
6	 * flow to show when entering a project directory.
7	 */
8	
9	import { existsSync, openSync, readSync, closeSync, readdirSync, readFileSync, statSync } from "node:fs";
