20	  state: "none" | "v1-planning" | "v2-gsd" | "v2-gsd-empty";
21	
22	  /** Is this the first time GSD has been used on this machine? */
23	  isFirstEverLaunch: boolean;
24	
25	  /** Does ~/.gsd/ exist with preferences? */
26	  hasGlobalSetup: boolean;
27	
28	  /** v1 details (only when state === 'v1-planning') */
29	  v1?: V1Detection;
30	
31	  /** v2 details (only when state === 'v2-gsd' or 'v2-gsd-empty') */
32	  v2?: V2Detection;
33	
34	  /** Detected project ecosystem signals */
35	  projectSignals: ProjectSignals;
36	}
