51	/** Apple platform SDKROOTs found in Xcode project.pbxproj files. */
52	export type XcodePlatform = "iphoneos" | "macosx" | "watchos" | "appletvos" | "xros";
53	
54	export interface ProjectSignals {
55	  /** Detected project/package files */
56	  detectedFiles: string[];
57	  /** Is this already a git repo? */
58	  isGitRepo: boolean;
59	  /** Is this a monorepo? */
