64	  xcodePlatforms: XcodePlatform[];
65	  /** Has existing CI configuration? */
66	  hasCI: boolean;
67	  /** Has existing test setup? */
68	  hasTests: boolean;
69	  /** Detected package manager */
70	  packageManager?: string;
71	  /** Auto-detected verification commands */
72	  verificationCommands: string[];
