381	// ─── Project Signals Detection ──────────────────────────────────────────────────
382	
383	/**
384	 * Quick filesystem scan for project ecosystem markers.
385	 * Reads only file existence + minimal content (package.json for monorepo/scripts).
386	 */
387	export function detectProjectSignals(basePath: string): ProjectSignals {
388	  const detectedFiles: string[] = [];
389	  let primaryLanguage: string | undefined;
390	
391	  // Detect project files
392	  for (const file of PROJECT_FILES) {
393	    if (existsSync(join(basePath, file))) {
394	      detectedFiles.push(file);
395	      if (!primaryLanguage) {
396	        primaryLanguage = LANGUAGE_MAP[file];
397	      }
398	    }
399	  }
400	
401	  // Bounded recursive scan for nested markers and dependency files.
402	  // This covers common brownfield layouts like src/App/App.csproj,
403	  // db/migrations/*.sql, src/components/*.vue, and services/api/pyproject.toml
404	  // without walking the entire repo or diving into heavyweight folders.
405	  const scannedFiles = scanProjectFiles(basePath);
406	
407	  for (const file of PROJECT_FILES) {
408	    if (detectedFiles.includes(file) || ROOT_ONLY_PROJECT_FILES.has(file)) continue;
409	    const hasMatch = file === "requirements.txt"
410	      ? scannedFiles.some(isPythonRequirementsFile)
411	      : scannedFiles.some((scannedFile) => matchesProjectFileMarker(scannedFile, file));
412	    if (hasMatch) {
413	      pushUnique(detectedFiles, file);
414	      if (!primaryLanguage && LANGUAGE_MAP[file]) {
415	        primaryLanguage = LANGUAGE_MAP[file];
416	      }
417	    }
418	  }
419	
420	  if (scannedFiles.some((file) => SQLITE_EXTENSIONS.some((ext) => file.endsWith(ext)))) {
421	    pushUnique(detectedFiles, "*.sqlite");
422	  }
423	  if (scannedFiles.some((file) => SQL_EXTENSIONS.some((ext) => file.endsWith(ext)))) {
424	    pushUnique(detectedFiles, "*.sql");
425	  }
426	
427	  const hasCsproj = scannedFiles.some((file) => file.endsWith(".csproj"));
428	  const hasFsproj = scannedFiles.some((file) => file.endsWith(".fsproj"));
429	  const hasSln = scannedFiles.some((file) => file.endsWith(".sln"));
430	
431	  if (hasCsproj) {
432	    pushUnique(detectedFiles, "*.csproj");
433	    if (!primaryLanguage) primaryLanguage = "csharp";
434	  }
435	  if (hasFsproj) {
436	    pushUnique(detectedFiles, "*.fsproj");
437	    if (!primaryLanguage) primaryLanguage = "fsharp";
438	  }
439	  if (hasSln) {
440	    pushUnique(detectedFiles, "*.sln");
441	    if (!primaryLanguage) primaryLanguage = "dotnet";
442	  }
443	
444	  if (scannedFiles.some((file) => VUE_EXTENSIONS.some((ext) => file.endsWith(ext)))) {
445	    pushUnique(detectedFiles, "*.vue");
446	  }
447	
448	  // Python framework detection — scan dependency files for framework-specific packages.
449	  // Adds synthetic markers (e.g. "dep:fastapi") so skill catalog matchFiles can reference them.
450	  const dependencyFiles = scannedFiles.filter((file) =>
451	    isPythonRequirementsFile(file) || file.endsWith("pyproject.toml"),
452	  );
453	  if (containsFastapiDependency(basePath, dependencyFiles)) {
454	    pushUnique(detectedFiles, "dep:fastapi");
455	  }
456	
457	  const springBootBuildFiles = scannedFiles.filter((file) =>
458	    file.endsWith("pom.xml") || file.endsWith("build.gradle") || file.endsWith("build.gradle.kts"),
459	  );
460	  const springBootVersionCatalogs = scannedFiles.filter((file) => file.endsWith(".versions.toml"));
461	  const springBootSettingsFiles = scannedFiles.filter((file) =>
462	    file.endsWith("settings.gradle") || file.endsWith("settings.gradle.kts"),
463	  );
464	  if (containsSpringBootMarker(basePath, springBootBuildFiles, springBootVersionCatalogs, springBootSettingsFiles)) {
465	    pushUnique(detectedFiles, "dep:spring-boot");
466	    if (!primaryLanguage) {
467	      primaryLanguage = "java/kotlin";
468	    }
469	  }
470	
471	  // Git repo detection
472	  const isGitRepo = existsSync(join(basePath, ".git"));
473	
474	  // Xcode platform detection — parse SDKROOT from project.pbxproj
475	  const xcodePlatforms = detectXcodePlatforms(basePath);
476	
477	  // Set primaryLanguage to swift when an Xcode project is found but no
478	  // Package.swift was detected (CocoaPods or SPM-less projects).
479	  if (!primaryLanguage && xcodePlatforms.length > 0) {
480	    primaryLanguage = "swift";
481	  }
482	
483	  // Monorepo detection
484	  let isMonorepo = false;
485	  for (const marker of MONOREPO_MARKERS) {
486	    if (existsSync(join(basePath, marker))) {
487	      isMonorepo = true;
488	      break;
489	    }
490	  }
491	  // Also check package.json workspaces
492	  if (!isMonorepo && detectedFiles.includes("package.json")) {
493	    isMonorepo = packageJsonHasWorkspaces(basePath);
494	  }
495	
496	  // CI detection
497	  let hasCI = false;
498	  for (const marker of CI_MARKERS) {
499	    if (existsSync(join(basePath, marker))) {
500	      hasCI = true;
501	      break;
502	    }
503	  }
504	
505	  // Test detection
506	  let hasTests = false;
507	  for (const marker of TEST_MARKERS) {
508	    if (existsSync(join(basePath, marker))) {
509	      hasTests = true;
510	      break;
511	    }
512	  }
513	
514	  // Package manager detection
515	  const packageManager = detectPackageManager(basePath);
516	
517	  // Verification commands
518	  const verificationCommands = detectVerificationCommands(basePath, detectedFiles, packageManager);
519	
520	  return {
521	    detectedFiles,
522	    isGitRepo,
523	    isMonorepo,
524	    primaryLanguage,
525	    xcodePlatforms,
526	    hasCI,
527	    hasTests,
528	    packageManager,
529	    verificationCommands,
530	  };
531	}
532	
533	// ─── Xcode Platform Detection ───────────────────────────────────────────────────
534	
535	/** Known SDKROOT values → canonical platform names. */
536	const SDKROOT_MAP: Record<string, XcodePlatform> = {
537	  iphoneos: "iphoneos",
538	  iphonesimulator: "iphoneos",      // simulator builds still target iOS
539	  macosx: "macosx",
540	  watchos: "watchos",
541	  watchsimulator: "watchos",
542	  appletvos: "appletvos",
543	  appletvsimulator: "appletvos",
544	  xros: "xros",
545	  xrsimulator: "xros",
546	};
547	
548	/** Regex for SUPPORTED_PLATFORMS — fallback when SDKROOT = auto (Xcode 15+). */
549	const SUPPORTED_PLATFORMS_RE = /SUPPORTED_PLATFORMS\s*=\s*"([^"]+)"/gi;
550	
551	/** Read at most `maxBytes` from a file without loading the full file into memory. */
552	function readBounded(filePath: string, maxBytes: number): string {
553	  const buf = Buffer.alloc(maxBytes);
554	  const fd = openSync(filePath, "r");
555	  try {
556	    const bytesRead = readSync(fd, buf, 0, maxBytes, 0);
557	    return buf.toString("utf-8", 0, bytesRead);
558	  } finally {
559	    closeSync(fd);
560	  }
561	}
562	
563	/** Common subdirectories where .xcodeproj may live in monorepos / standard layouts. */
564	const XCODE_SUBDIRS = ["ios", "macos", "app", "apps"] as const;
565	
566	/**
567	 * Scan *.xcodeproj directories for project.pbxproj and extract SDKROOT values.
568	 * Returns deduplicated, canonical platform list (e.g. ["iphoneos"]).
569	 *
570	 * Reading the pbxproj is a lightweight regex scan — no full plist parsing needed.
571	 * We read at most 1 MB per file to keep detection fast.
572	 * Searches both the project root and common subdirectories (ios/, macos/, app/).
573	 */
574	function detectXcodePlatforms(basePath: string): XcodePlatform[] {
575	  const platforms = new Set<XcodePlatform>();
576	
577	  // Directories to scan: project root + common subdirs
578	  const dirsToScan = [basePath];
579	  for (const sub of XCODE_SUBDIRS) {
580	    const subPath = join(basePath, sub);
581	    if (existsSync(subPath)) dirsToScan.push(subPath);
582	  }
583	
584	  for (const dir of dirsToScan) {
585	    try {
586	      const entries = readdirSync(dir, { withFileTypes: true });
587	      for (const entry of entries) {
588	        if (!entry.isDirectory() || !entry.name.endsWith(".xcodeproj")) continue;
589	        const pbxprojPath = join(dir, entry.name, "project.pbxproj");
590	        try {
591	          const content = readBounded(pbxprojPath, 1024 * 1024);
592	          // Match SDKROOT = <value>; — both quoted and unquoted forms
593	          const sdkRe = /SDKROOT\s*=\s*"?([a-z]+)"?\s*;/gi;
594	          let m: RegExpExecArray | null;
595	          let foundExplicit = false;
596	          while ((m = sdkRe.exec(content)) !== null) {
597	            const val = m[1].toLowerCase();
598	            if (val === "auto") continue; // handled below via SUPPORTED_PLATFORMS
599	            const canonical = SDKROOT_MAP[val];
600	            if (canonical) {
601	              platforms.add(canonical);
602	              foundExplicit = true;
603	            }
604	          }
605	          // Xcode 15+ defaults SDKROOT to "auto"; fall back to SUPPORTED_PLATFORMS
606	          if (!foundExplicit) {
607	            let sp: RegExpExecArray | null;
608	            while ((sp = SUPPORTED_PLATFORMS_RE.exec(content)) !== null) {
609	              for (const tok of sp[1].split(/\s+/)) {
610	                const canonical = SDKROOT_MAP[tok.toLowerCase()];
611	                if (canonical) platforms.add(canonical);
612	              }
613	            }
614	            SUPPORTED_PLATFORMS_RE.lastIndex = 0;
615	          }
616	        } catch {
617	          // unreadable pbxproj — skip
618	        }
619	      }
620	    } catch {
621	      // unreadable directory
622	    }
623	  }
624	  return [...platforms];
625	}
626	
627	// ─── Package Manager Detection ──────────────────────────────────────────────────
628	
629	function detectPackageManager(basePath: string): string | undefined {
630	  if (existsSync(join(basePath, "pnpm-lock.yaml"))) return "pnpm";
631	  if (existsSync(join(basePath, "yarn.lock"))) return "yarn";
632	  if (existsSync(join(basePath, "bun.lockb")) || existsSync(join(basePath, "bun.lock"))) return "bun";
633	  if (existsSync(join(basePath, "package-lock.json"))) return "npm";
634	  if (existsSync(join(basePath, "package.json"))) return "npm";
635	  return undefined;
636	}
637	
638	// ─── Verification Command Detection ─────────────────────────────────────────────
639	
640	/**
641	 * Auto-detect verification commands from project files.
642	 * Returns commands in priority order (test first, then build, then lint).
643	 */
644	function detectVerificationCommands(
645	  basePath: string,
646	  detectedFiles: string[],
647	  packageManager?: string,
648	): string[] {
649	  const commands: string[] = [];
650	  const pm = packageManager ?? "npm";
651	  const run = pm === "npm" ? "npm run" : pm === "yarn" ? "yarn" : pm === "bun" ? "bun run" : `${pm} run`;
652	
653	  if (detectedFiles.includes("package.json")) {
654	    const scripts = readPackageJsonScripts(basePath);
655	    if (scripts) {
656	      // Test commands (highest priority)
657	      if (scripts.test && scripts.test !== "echo \"Error: no test specified\" && exit 1") {
658	        commands.push(pm === "npm" ? "npm test" : `${pm} test`);
659	      }
660	      // Build commands
661	      if (scripts.build) {
662	        commands.push(`${run} build`);
663	      }
664	      // Lint commands
665	      if (scripts.lint) {
666	        commands.push(`${run} lint`);
667	      }
668	      // Typecheck commands
669	      if (scripts.typecheck) {
670	        commands.push(`${run} typecheck`);
671	      } else if (scripts.tsc) {
672	        commands.push(`${run} tsc`);
673	      }
674	    }
675	  }
676	
677	  if (detectedFiles.includes("Cargo.toml")) {
678	    commands.push("cargo test");
679	    commands.push("cargo clippy");
680	  }
681	
682	  if (detectedFiles.includes("go.mod")) {
683	    commands.push("go test ./...");
684	    commands.push("go vet ./...");
685	  }
686	
687	  if (detectedFiles.includes("pyproject.toml") || detectedFiles.includes("setup.py") || detectedFiles.includes("requirements.txt")) {
688	    commands.push("pytest");
689	  }
690	
691	  if (detectedFiles.includes("Gemfile")) {
692	    // Check for rspec vs minitest
693	    if (existsSync(join(basePath, "spec"))) {
694	      commands.push("bundle exec rspec");
695	    } else {
696	      commands.push("bundle exec rake test");
697	    }
698	  }
699	
700	  if (detectedFiles.includes("Makefile")) {
701	    const makeTargets = readMakefileTargets(basePath);
702	    if (makeTargets.includes("test")) {
703	      commands.push("make test");
704	    }
705	  }
706	
707	  return commands;
708	}
709	
710	// ─── Global Setup Detection ─────────────────────────────────────────────────────
711	
712	/**
713	 * Check if global GSD setup exists (has ~/.gsd/ with preferences).
714	 */
715	export function hasGlobalSetup(): boolean {
716	  return (
717	    existsSync(join(gsdHome, "preferences.md")) ||
718	    existsSync(join(gsdHome, "PREFERENCES.md"))
719	  );
720	}
721	
722	/**
723	 * Check if this is the very first time GSD has been used on this machine.
724	 * Returns true if ~/.gsd/ doesn't exist or has no preferences or auth.
725	 */
726	export function isFirstEverLaunch(): boolean {
727	  if (!existsSync(gsdHome)) return true;
728	
729	  // If we have preferences, not first launch
730	  if (
731	    existsSync(join(gsdHome, "preferences.md")) ||
732	    existsSync(join(gsdHome, "PREFERENCES.md"))
733	  ) {
734	    return false;
735	  }
736	
737	  // If we have auth.json, not first launch (onboarding.ts already ran)
738	  if (existsSync(join(gsdHome, "agent", "auth.json"))) return false;
739	
740	  // Check legacy path too
741	  const legacyPath = join(homedir(), ".pi", "agent", "gsd-preferences.md");
742	  if (existsSync(legacyPath)) return false;
743	
744	  return true;
745	}
746	
747	// ─── Helpers ────────────────────────────────────────────────────────────────────
748	
749	function packageJsonHasWorkspaces(basePath: string): boolean {
750	  try {
751	    const raw = readFileSync(join(basePath, "package.json"), "utf-8");
752	    const pkg = JSON.parse(raw);
753	    return Array.isArray(pkg.workspaces) || (pkg.workspaces && typeof pkg.workspaces === "object");
754	  } catch {
755	    return false;
756	  }
757	}
758	
759	function readPackageJsonScripts(basePath: string): Record<string, string> | null {
760	  try {
761	    const raw = readFileSync(join(basePath, "package.json"), "utf-8");
762	    const pkg = JSON.parse(raw);
763	    return pkg.scripts && typeof pkg.scripts === "object" ? pkg.scripts : null;
764	  } catch {
765	    return null;
766	  }
767	}
768	
769	function readMakefileTargets(basePath: string): string[] {
770	  try {
771	    const raw = readFileSync(join(basePath, "Makefile"), "utf-8");
772	    const targets: string[] = [];
773	    for (const line of raw.split("\n")) {
774	      const match = line.match(/^([a-zA-Z_][a-zA-Z0-9_-]*):/);
775	      if (match) targets.push(match[1]);
776	    }
777	    return targets;
778	  } catch {
779	    return [];
780	  }
781	}
782	
783	function pushUnique(arr: string[], value: string): void {
784	  if (!arr.includes(value)) arr.push(value);
785	}
786	
787	function matchesProjectFileMarker(scannedFile: string, marker: string): boolean {
788	  const normalized = scannedFile.replaceAll("\\", "/");
789	  return (
790	    normalized === marker ||
791	    normalized.endsWith(`/${marker}`)
792	  );
793	}
794	
795	function isPythonRequirementsFile(relativePath: string): boolean {
796	  const normalized = relativePath.replaceAll("\\", "/");
797	  const basename = normalized.slice(normalized.lastIndexOf("/") + 1);
798	  return (
799	    basename === "requirements.txt" ||
800	    basename === "requirements.in" ||
801	    /^requirements([-.].+)?\.(txt|in)$/i.test(basename) ||
802	    /(^|\/)requirements\/.+\.(txt|in)$/i.test(normalized)
803	  );
804	}
805	
806	function containsFastapiDependency(basePath: string, relativePaths: string[]): boolean {
807	  for (const relativePath of relativePaths) {
808	    try {
809	      const raw = readBounded(join(basePath, relativePath), 64 * 1024);
810	      const content = extractDependencyContent(relativePath, raw);
811	      if (isPythonRequirementsFile(relativePath)) {
812	        for (const line of content.split("\n")) {
813	          if (extractRequirementName(line) === "fastapi") return true;
814	        }
815	        continue;
816	      }
817	
818	      if (relativePath.endsWith("pyproject.toml")) {
819	        if (containsFastapiInPyproject(content)) return true;
820	      }
821	    } catch {
822	      // unreadable file — continue scanning other candidate files
823	    }
824	  }
825	
826	  return false;
827	}
828	
829	function containsSpringBootMarker(
830	  basePath: string,
831	  buildFiles: string[],
832	  versionCatalogFiles: string[],
833	  settingsFiles: string[],
834	): boolean {
835	  const usedPluginAliases = new Set<string>();
836	  const usedLibraryAliases = new Set<string>();
837	  const catalogAccessors = resolveVersionCatalogAccessors(basePath, versionCatalogFiles, settingsFiles);
838	
839	  for (const relativePath of buildFiles) {
840	    try {
841	      const raw = readBounded(join(basePath, relativePath), 64 * 1024);
842	      const content = stripDependencyComments(relativePath, raw);
843	      if (containsDirectSpringBootReference(relativePath, content)) {
844	        return true;
845	      }
846	
847	      const normalized = content.toLowerCase();
848	      let match: RegExpExecArray | null;
849	      for (const accessor of catalogAccessors) {
850	        const aliasRe = new RegExp(`alias\\(\\s*${accessor}\\.plugins\\.([a-z0-9_.-]+)\\s*\\)`, "gi");
851	        while ((match = aliasRe.exec(normalized)) !== null) {
852	          usedPluginAliases.add(normalizePluginAlias(match[1]));
853	        }
854	
855	        const libraryAliasRe = new RegExp(`\\b${accessor}\\.((?!plugins\\b)[a-z0-9_.-]+)`, "gi");
856	        while ((match = libraryAliasRe.exec(normalized)) !== null) {
857	          usedLibraryAliases.add(normalizePluginAlias(match[1]));
858	        }
859	      }
860	    } catch {
861	      // unreadable build file — continue scanning others
862	    }
863	  }
864	
865	  if (usedPluginAliases.size === 0 && usedLibraryAliases.size === 0) {
866	    return false;
867	  }
868	  if (versionCatalogFiles.length === 0) {
869	    return false;
870	  }
871	
872	  const springBootAliases = new Set<string>();
873	  const springBootLibraries = new Set<string>();
874	  const pendingSpringBootBundles: Array<{ bundleAlias: string; referencedAliases: string[] }> = [];
875	  for (const relativePath of versionCatalogFiles) {
876	    try {
877	      const raw = readBounded(join(basePath, relativePath), 64 * 1024);
878	      const content = stripDependencyComments(relativePath, raw);
879	      const aliasRe = /^\s*([A-Za-z0-9_.-]+)\s*=\s*\{[^\n}]*\bid\s*=\s*["']org\.springframework\.boot["'][^\n}]*\}/gm;
880	      let match: RegExpExecArray | null;
881	      while ((match = aliasRe.exec(content)) !== null) {
882	        springBootAliases.add(normalizePluginAlias(match[1]));
883	      }
884	
885	      const libraryRe = /^\s*([A-Za-z0-9_.-]+)\s*=\s*\{[^\n}]*\b(module\s*=\s*["']org\.springframework\.boot:[^"']+["']|group\s*=\s*["']org\.springframework\.boot["'][^\n}]*\bname\s*=\s*["']spring-boot[^"']*["'])[^\n}]*\}/gm;
886	      while ((match = libraryRe.exec(content)) !== null) {
887	        springBootLibraries.add(normalizePluginAlias(match[1]));
888	      }
889	
890	      const bundleRe = /^\s*([A-Za-z0-9_.-]+)\s*=\s*\[([\s\S]*?)\]/gm;
891	      while ((match = bundleRe.exec(content)) !== null) {
892	        pendingSpringBootBundles.push({
893	          bundleAlias: normalizePluginAlias(`bundles.${match[1]}`),
894	          referencedAliases: match[2]
895	            .split(",")
896	            .map((part) => normalizePluginAlias(part.replace(/["'\s]/g, "")))
897	            .filter(Boolean),
898	        });
899	      }
900	    } catch {
901	      // unreadable version catalog — continue scanning others
902	    }
903	  }
904	
905	  const springBootBundles = new Set<string>();
906	  for (const pendingBundle of pendingSpringBootBundles) {
907	    if (pendingBundle.referencedAliases.some((alias) => springBootLibraries.has(alias))) {
908	      springBootBundles.add(pendingBundle.bundleAlias);
909	    }
910	  }
911	
912	  for (const alias of usedPluginAliases) {
913	    if (springBootAliases.has(alias)) return true;
914	  }
915	  for (const alias of usedLibraryAliases) {
916	    if (springBootLibraries.has(alias) || springBootBundles.has(alias)) return true;
917	  }
918	
919	  return false;
920	}
921	
922	function stripDependencyComments(relativePath: string, content: string): string {
923	  if (relativePath.endsWith("requirements.txt")) {
924	    return content.replace(/(^|\s)#.*$/gm, "");
925	  }
926	  if (relativePath.endsWith("pyproject.toml")) {
927	    return content.replace(/(^|\s)#.*$/gm, "");
928	  }
929	  if (relativePath.endsWith(".versions.toml")) {
930	    return content.replace(/(^|\s)#.*$/gm, "");
931	  }
932	  if (relativePath.endsWith("settings.gradle") || relativePath.endsWith("settings.gradle.kts")) {
933	    return content
934	      .replace(/\/\*[\s\S]*?\*\//g, "")
935	      .replace(/\/\/.*$/gm, "");
936	  }
937	  if (relativePath.endsWith("pom.xml")) {
938	    return content.replace(/<!--[\s\S]*?-->/g, "");
939	  }
940	  if (relativePath.endsWith("build.gradle") || relativePath.endsWith("build.gradle.kts")) {
941	    return content
942	      .replace(/\/\*[\s\S]*?\*\//g, "")
943	      .replace(/\/\/.*$/gm, "");
944	  }
945	  return content;
946	}
947	
948	function extractDependencyContent(relativePath: string, content: string): string {
949	  const stripped = stripDependencyComments(relativePath, content);
950	  if (relativePath.endsWith("pyproject.toml")) {
951	    return extractPyprojectDependencySections(stripped);
952	  }
953	  return stripped;
954	}
955	
956	function extractRequirementName(spec: string): string | null {
957	  const trimmed = spec.trim().replace(/^["']|["']$/g, "");
958	  if (!trimmed) return null;
959	
960	  const match = trimmed.match(/^([A-Za-z0-9_.-]+)(?:\[[^\]]+\])?(?=\s*(?:@|[<>=!~;]|$))/);
961	  if (!match) return null;
962	  return normalizePackageName(match[1]);
963	}
964	
965	function containsFastapiInPyproject(content: string): boolean {
966	  for (const line of content.split("\n")) {
967	    const keyMatch = line.match(/^\s*([A-Za-z0-9_.-]+)\s*=/);
968	    if (keyMatch) {
969	      const key = normalizePackageName(keyMatch[1]);
970	      if (key === "fastapi") {
971	        return true;
972	      }
973	      if (key !== "dependencies") {
974	        continue;
975	      }
976	    }
977	
978	    const quotedSpecRe = /["']([^"']+)["']/g;
979	    let match: RegExpExecArray | null;
980	    while ((match = quotedSpecRe.exec(line)) !== null) {
981	      if (extractRequirementName(match[1]) === "fastapi") {
982	        return true;
983	      }
984	    }
985	  }
986	
987	  return false;
988	}
989	
990	function containsDirectSpringBootReference(relativePath: string, content: string): boolean {
991	  if (relativePath.endsWith("pom.xml")) {
992	    return /<groupId>\s*org\.springframework\.boot\s*<\/groupId>/i.test(content);
993	  }
994	
995	  if (relativePath.endsWith("build.gradle") || relativePath.endsWith("build.gradle.kts")) {
996	    return /(id\s*\(?\s*["']org\.springframework\.boot["']|apply\s*\(?\s*plugin\s*[:=]\s*["']org\.springframework\.boot["']|(?:implementation|api|compileOnly|runtimeOnly|testImplementation|annotationProcessor|kapt)\s*\(?\s*["'][^"']*org\.springframework\.boot:[^"']*spring-boot[^"']*["'])/i.test(content);
997	  }
998	
999	  return false;
1000	}
1001	
1002	function extractPyprojectDependencySections(content: string): string {
1003	  const lines = content.split("\n");
1004	  const collected: string[] = [];
1005	  let section = "";
1006	  let collectingProjectDeps = false;
1007	  let collectingOptionalDeps = false;
1008	  let bracketDepth = 0;
1009	
1010	  for (const line of lines) {
1011	    const trimmed = line.trim();
1012	
1013	    if (collectingProjectDeps) {
1014	      collected.push(line);
1015	      bracketDepth += countChar(line, "[") - countChar(line, "]");
1016	      if (bracketDepth <= 0) {
1017	        collectingProjectDeps = false;
1018	      }
1019	      continue;
1020	    }
1021	
1022	    if (collectingOptionalDeps) {
1023	      collected.push(line);
1024	      bracketDepth += countChar(line, "[") - countChar(line, "]");
1025	      if (bracketDepth <= 0) {
1026	        collectingOptionalDeps = false;
1027	      }
1028	      continue;
1029	    }
1030	
1031	    const sectionMatch = trimmed.match(/^\[([^\]]+)\]$/);
1032	    if (sectionMatch) {
1033	      section = sectionMatch[1].trim();
1034	      continue;
1035	    }
1036	
1037	    if (section === "project" && /^dependencies\s*=\s*\[/.test(trimmed)) {
1038	      collected.push(line);
1039	      bracketDepth = countChar(line, "[") - countChar(line, "]");
1040	      collectingProjectDeps = bracketDepth > 0;
1041	      continue;
1042	    }
1043	
1044	    if (
1045	      section === "project.optional-dependencies" ||
1046	      section === "tool.poetry.dependencies"
1047	    ) {
1048	      if (section === "project.optional-dependencies") {
1049	        const equalsIndex = line.indexOf("=");
1050	        if (equalsIndex !== -1) {
1051	          const value = line.slice(equalsIndex + 1);
1052	          collected.push(value);
1053	          bracketDepth = countChar(value, "[") - countChar(value, "]");
1054	          collectingOptionalDeps = bracketDepth > 0;
1055	        }
1056	      } else {
1057	        collected.push(line);
1058	      }
1059	    }
1060	  }
1061	
1062	  return collected.join("\n");
1063	}
1064	
1065	function countChar(text: string, char: string): number {
1066	  return [...text].filter((c) => c === char).length;
1067	}
1068	
1069	function normalizePackageName(name: string): string {
1070	  return name.toLowerCase().replace(/[_.]/g, "-");
1071	}
1072	
1073	function normalizePluginAlias(alias: string): string {
1074	  return alias.toLowerCase().replace(/[-_]/g, ".");
1075	}
1076	
1077	function versionCatalogAccessorName(relativePath: string): string {
1078	  const normalized = relativePath.replaceAll("\\", "/");
1079	  const basename = normalized.slice(normalized.lastIndexOf("/") + 1);
1080	  return basename.replace(/\.versions\.toml$/i, "").toLowerCase();
1081	}
1082	
1083	function resolveVersionCatalogAccessors(
1084	  basePath: string,
1085	  versionCatalogFiles: string[],
1086	  settingsFiles: string[],
1087	): Set<string> {
1088	  const accessors = new Set(versionCatalogFiles.map(versionCatalogAccessorName).filter(Boolean));
1089	  if (versionCatalogFiles.length === 0 || settingsFiles.length === 0) {
1090	    return accessors;
1091	  }
1092	
1093	  for (const settingsFile of settingsFiles) {
1094	    try {
1095	      const raw = readBounded(join(basePath, settingsFile), 64 * 1024);
1096	      const content = stripDependencyComments(settingsFile, raw);
1097	      const createRe = /create\(\s*["']([A-Za-z0-9_]+)["']\s*\)\s*\{[\s\S]*?([A-Za-z0-9_.-]+\.versions\.toml)["']?\s*\)\s*\)/g;
1098	      let match: RegExpExecArray | null;
1099	      while ((match = createRe.exec(content)) !== null) {
1100	        const accessor = match[1].toLowerCase();
1101	        const catalogBasename = match[2].replaceAll("\\", "/").split("/").pop()!;
1102	        if (versionCatalogFiles.some((file) => {
1103	          const normalized = file.replaceAll("\\", "/");
1104	          return normalized === catalogBasename || normalized.endsWith(`/${catalogBasename}`);
1105	        })) {
1106	          accessors.add(accessor);
1107	        }
1108	      }
1109	    } catch {
1110	      // unreadable settings file — ignore
1111	    }
1112	  }
1113	
1114	  return accessors;
1115	}
1116	
1117	function scanProjectFiles(basePath: string): string[] {
1118	  const files: string[] = [];
1119	  const queue: Array<{ path: string; depth: number }> = [{ path: basePath, depth: 0 }];
1120	
1121	  while (queue.length > 0 && files.length < MAX_RECURSIVE_SCAN_FILES) {
1122	    const current = queue.shift()!;
1123	    let entries: Array<{ name: string; isDirectory(): boolean; isFile(): boolean }>;
1124	    try {
1125	      entries = readdirSync(current.path, { withFileTypes: true, encoding: "utf8" });
1126	    } catch {
1127	      continue;
1128	    }
1129	
1130	    for (const entry of entries) {
1131	      const entryPath = join(current.path, entry.name);
1132	      const relativePath = entryPath.slice(basePath.length + 1);
1133	
1134	      if (entry.isDirectory()) {
1135	        if (current.depth < MAX_RECURSIVE_SCAN_DEPTH && !RECURSIVE_SCAN_IGNORED_DIRS.has(entry.name)) {
1136	          queue.push({ path: entryPath, depth: current.depth + 1 });
1137	        }
1138	        continue;
1139	      }
1140	
1141	      if (!entry.isFile()) continue;
1142	      files.push(relativePath);
1143	      if (files.length >= MAX_RECURSIVE_SCAN_FILES) break;
1144	    }
1145	  }
1146	
1147	  return files;
1148	}
1149	

